// Solo filas reales de tecnicos (evita el item de error de 'continueErrorOutput')
const techs = $input.all().filter((i) => i.json && i.json.calendar_id);

// Sin tecnicos disponibles: devolvemos lista vacia controlada
if (techs.length === 0) {
  return [{ json: { available_slots: [] } }];
}

const now = new Date();
const pad = (n) => n.toString().padStart(2, '0');
const offset = "-05:00";
const toBogotaISO = (d) => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:00:00${offset}`;

const slots = [];
if (now.getHours() < 16) {
  const slotHoy = new Date(now);
  slotHoy.setHours(now.getHours() + 2);
  slots.push({
    date_iso: toBogotaISO(slotHoy),
    technician_name: techs[0].json.full_name,
    calendar_id: techs[0].json.calendar_id
  });
}

const slotManana = new Date(now);
slotManana.setDate(slotManana.getDate() + 1);
slotManana.setHours(9);
// Si solo hay un tecnico, reutilizamos el mismo (no rompe con techs[1] undefined)
const tech2 = techs[1] || techs[0];
slots.push({
  date_iso: toBogotaISO(slotManana),
  technician_name: tech2.json.full_name,
  calendar_id: tech2.json.calendar_id
});

return [{ json: { available_slots: slots } }];

// Read the incoming JSON from the Vapi Webhook
const payload = $input.first().json.body.message;
const toolCall = payload.toolCalls[0];

// Extract arguments bypassing n8n's strict security check
const rawArgs = toolCall.function["arguments"];

// Check the data type to avoid the [object Object] parsing error
let parsedArgs = {};
if (typeof rawArgs === 'string') {
    parsedArgs = JSON.parse(rawArgs || "{}");
} else if (typeof rawArgs === 'object' && rawArgs !== null) {
    parsedArgs = rawArgs; // Already an object, no need to parse
}

// Numero del que llama (para reconocer, cancelar o reprogramar citas en re-llamadas)
const phone = (payload.call && payload.call.customer && payload.call.customer.number)
  ? payload.call.customer.number
  : ((payload.customer && payload.customer.number) ? payload.customer.number : null);

// Return a clean, flat object for the rest of the workflow
return {
  call_id: payload.call.id,
  phone: phone,
  tool_call_id: toolCall.id,
  tool_name: toolCall.function.name,
  args: parsedArgs
};

